"use client";
import { useState, useEffect, useRef } from "react";
import { colord, extend } from "colord";
import mixPlugin from "colord/plugins/mix";

extend([mixPlugin]);

export default function Home() {
  const [connectionStrength, setConnectionStrength] = useState(98.4);
  
  // Ham tinh toan mau sac dua tren do tin cay (Connection Strength)
  // 100% = Xanh luc, 0% = Do
  const getStrengthColor = (strength) => {
    return colord("#ef4444").mix("#22c55e", strength / 100).toHslString();
  };
  const [messages, setMessages] = useState([
    { 
      role: "assistant", 
      content: "Chào mừng bạn đến với JurisLogic. Tôi đã sẵn sàng phân tích hành vi vi phạm dựa trên Đồ thị tri thức.",
      type: "intro"
    }
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMessage = { role: "user", content: input };
    setMessages((prev) => [...prev, userMessage]);
    setInput("");
    setIsLoading(true);

    try {
      const response = await fetch("http://localhost:8000/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: input }),
      });
      const data = await response.json();
      
      // Logic parse du lieu de hien thi card dep nhu anh
      setMessages((prev) => [...prev, { 
        role: "assistant", 
        content: data.answer,
        type: "analysis"
      }]);
    } catch (error) {
      setMessages((prev) => [...prev, { role: "assistant", content: "Lỗi kết nối hệ thống.", type: "error" }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <main className="flex h-screen bg-[#F8FAFC] text-slate-900 font-sans overflow-hidden">
      
      {/* LEFT SIDEBAR */}
      <div className="w-64 bg-white border-r border-slate-200 flex flex-col p-6 shadow-sm z-20">
        <div className="mb-10">
          <h1 className="text-2xl font-black text-[#1E293B] tracking-tighter">JurisLogic</h1>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">GraphRAG Engine</p>
        </div>
        
        <nav className="flex-1 space-y-2">
          {["Dashboard", "AI Assistant", "Law Database", "Settings"].map((item) => (
            <div key={item} className={`flex items-center gap-3 px-4 py-3 rounded-xl cursor-pointer transition-all ${item === 'AI Assistant' ? 'bg-[#F1F5F9] text-blue-600 font-bold border-r-4 border-blue-600' : 'text-slate-500 hover:bg-slate-50'}`}>
              <span className="text-lg">{item === 'Dashboard' ? '📊' : item === 'AI Assistant' ? '🤖' : item === 'Law Database' ? '🏛️' : '⚙️'}</span>
              <span className="text-sm">{item}</span>
            </div>
          ))}
        </nav>

        <div className="mt-auto space-y-4">
          <button className="w-full bg-[#0F172A] text-white py-3 rounded-xl font-bold text-sm shadow-lg hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
            <span>+</span> New Analysis
          </button>
          <div className="flex items-center gap-3 p-2 border-t border-slate-100 pt-4">
            <div className="w-10 h-10 bg-blue-100 rounded-full overflow-hidden flex items-center justify-center text-xl">👤</div>
            <div>
              <p className="text-xs font-bold">Minh Nguyen</p>
              <p className="text-[10px] text-slate-400">Legal Lead</p>
            </div>
          </div>
        </div>
      </div>

      {/* MIDDLE COLUMN: CHAT HUB */}
      <div className="flex-1 flex flex-col relative bg-white">
        {/* Topbar */}
        <div className="h-16 border-b border-slate-100 flex items-center px-8 justify-between">
          <div className="relative w-96">
            <input type="text" placeholder="Tìm kiếm tài liệu, án lệ..." className="w-full bg-slate-100 border-none rounded-full py-2 px-10 text-xs focus:ring-2 focus:ring-blue-500/20" />
            <span className="absolute left-4 top-2 text-slate-400">🔍</span>
          </div>
          <div className="flex items-center gap-6">
            <span className="text-xl cursor-pointer">🔔</span>
            <span className="text-xl cursor-pointer">❓</span>
            <div className="h-8 w-px bg-slate-200"></div>
            <span className="text-sm font-black text-[#1E293B]">JurisLogic GraphRAG</span>
          </div>
        </div>

        {/* Chat Messages */}
        <div className="flex-1 overflow-y-auto p-10 space-y-10 bg-[#F8FAFC]/50">
          {messages.map((m, idx) => (
            <div key={idx} className={`flex ${m.role === "user" ? "justify-end" : "justify-start"}`}>
              {m.role === "user" ? (
                <div className="flex items-start gap-3 flex-row-reverse">
                  <div className="w-8 h-8 bg-slate-800 rounded-lg flex items-center justify-center text-white text-xs">MN</div>
                  <div className="bg-white border border-slate-200 p-4 rounded-2xl rounded-tr-none shadow-sm text-sm font-medium max-w-md">
                    {m.content}
                  </div>
                </div>
              ) : (
                <div className="flex items-start gap-4 max-w-2xl w-full">
                  <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-500/20">⚖️</div>
                  <div className="flex-1 space-y-4">
                    <h3 className="font-black text-lg text-slate-800 flex items-center gap-2">
                      ▮ Phân tích hành vi: {input || "Hành vi vi phạm"}
                    </h3>
                    <div className="bg-white border border-slate-200 rounded-3xl p-8 shadow-sm space-y-6">
                      <p className="text-sm text-slate-600 leading-relaxed italic">
                        "Dựa trên cơ sở dữ liệu luật giao thông đường bộ Việt Nam, hành vi này được phân loại như sau:"
                      </p>
                      
                      {/* Violation Cards (Mockup for now) */}
                      <div className="grid gap-4">
                        <div className="p-5 border border-slate-100 rounded-2xl bg-slate-50/50 flex items-center gap-5">
                          <div className="text-3xl">🚗</div>
                          <div>
                            <p className="text-sm font-black uppercase text-slate-800">Ô tô:</p>
                            <p className="text-xs text-slate-500 mt-1">{m.content.slice(0, 150)}...</p>
                          </div>
                        </div>
                        <div className="p-5 border border-slate-100 rounded-2xl bg-slate-50/50 flex items-center gap-5">
                          <div className="text-3xl">🏍️</div>
                          <div>
                            <p className="text-sm font-black uppercase text-slate-800">Xe máy:</p>
                            <p className="text-xs text-slate-500 mt-1">Tra cứu nồng độ cồn và các mức phạt tương ứng...</p>
                          </div>
                        </div>
                      </div>

                      <div className="pt-4 border-t border-slate-100 flex items-center gap-3">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Logic Node Path:</span>
                        <div className="flex gap-2">
                          {['A', 'B', 'C'].map(node => (
                            <div key={node} className="w-6 h-6 bg-blue-900 rounded-full text-white text-[10px] flex items-center justify-center font-bold">{node}</div>
                          ))}
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              )}
            </div>
          ))}
          {isLoading && (
            <div className="flex items-center gap-3 text-blue-600 animate-pulse ml-14">
              <div className="w-2 h-2 bg-blue-600 rounded-full"></div>
              <span className="text-[10px] font-black uppercase tracking-widest">Analyzing Knowledge Graph...</span>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Input Bar */}
        <div className="p-10 bg-white border-t border-slate-100">
          <div className="max-w-3xl mx-auto relative flex items-center bg-white shadow-2xl rounded-2xl border border-slate-200 p-2">
            <span className="px-4 text-slate-400 text-xl cursor-pointer">📎</span>
            <span className="px-2 text-slate-400 text-xl cursor-pointer">🎤</span>
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && handleSend()}
              placeholder="Nhập câu hỏi pháp lý của bạn..." 
              className="flex-1 py-4 px-4 text-sm focus:outline-none" 
            />
            <button 
              onClick={handleSend}
              className="bg-[#0F172A] text-white p-4 rounded-xl hover:bg-slate-800 transition-all"
            >
              <span className="text-xl">✈️</span>
            </button>
          </div>
        </div>
      </div>

      {/* RIGHT SIDEBAR: LOGIC GRAPH */}
      <div className="w-[400px] bg-white border-l border-slate-200 p-10 flex flex-col overflow-hidden relative">
        <h2 className="text-2xl font-black text-slate-800 tracking-tight">Logic Graph</h2>
        <p className="text-xs text-slate-400 mt-1 font-medium">Visualizing reasoning connections</p>

        {/* MOCK GRAPH VISUALIZER (SVG) */}
        <div className="flex-1 flex items-center justify-center relative">
          <svg className="w-full h-full opacity-40 absolute top-0 left-0">
            <line x1="50%" y1="30%" x2="30%" y2="50%" stroke="#CBD5E1" strokeDasharray="4" />
            <line x1="50%" y1="30%" x2="70%" y2="50%" stroke="#CBD5E1" strokeDasharray="4" />
            <line x1="30%" y1="50%" x2="50%" y2="70%" stroke="#CBD5E1" strokeDasharray="4" />
          </svg>
          
          <div className="space-y-12 relative z-10 flex flex-col items-center">
            {/* Hanh Vi Node */}
            <div className="w-24 h-24 bg-[#0F172A] rounded-full flex flex-col items-center justify-center text-white border-8 border-slate-100 shadow-xl">
              <span className="text-2xl">⌨️</span>
              <span className="text-[8px] font-black uppercase mt-1">Hành vi</span>
            </div>

            <div className="flex gap-16">
              {/* Nghi Dinh Node */}
              <div className="w-16 h-16 bg-blue-600 rounded-full flex flex-col items-center justify-center text-white border-4 border-slate-100 shadow-lg">
                <span className="text-xl">📄</span>
                <span className="text-[6px] font-black uppercase mt-1">Nghị định</span>
              </div>
              {/* Tuoc GPLX Node */}
              <div className="w-16 h-16 bg-slate-800 rounded-full flex flex-col items-center justify-center text-white border-4 border-slate-100 shadow-lg">
                <span className="text-xl">⚠️</span>
                <span className="text-[6px] font-black uppercase mt-1">Tước GPLX</span>
              </div>
            </div>

            {/* Muc Phat Node */}
            <div className="w-20 h-20 bg-blue-500 rounded-full flex flex-col items-center justify-center text-white border-6 border-slate-100 shadow-xl">
              <span className="text-2xl">💰</span>
              <span className="text-[8px] font-black uppercase mt-1">Mức phạt</span>
            </div>
          </div>
        </div>

        {/* NODE DETAILS CARD */}
        <div className="bg-slate-50 border border-slate-200 rounded-2xl p-6 space-y-4">
          <div className="flex items-center gap-3">
            <span className="text-blue-600">🕸️</span>
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500">Node Details</h3>
          </div>
          <div className="space-y-1">
            <div className="flex justify-between items-end">
              <span className="text-xs font-bold">Connection Strength</span>
              <span className="text-xs font-black" style={{ color: getStrengthColor(connectionStrength) }}>{connectionStrength}%</span>
            </div>
            <div className="w-full bg-slate-200 h-1.5 rounded-full overflow-hidden">
              <div 
                className="h-full transition-all duration-1000" 
                style={{ 
                  width: `${connectionStrength}%`,
                  backgroundColor: getStrengthColor(connectionStrength)
                }}
              ></div>
            </div>
          </div>
          <p className="text-[10px] italic text-slate-400">
            "Xác định dựa trên Điều 5, Khoản 5, Điểm c của Nghị định 100."
          </p>
        </div>
      </div>
    </main>
  );
}
